$gp=@{}; foreach($l in $geoPathsRaw){ $i=$l.IndexOf('|'); $gp[$l.Substring(0,$i)]=$l.Substring($i+1) }
function BuildMap($rates){
  $svg="<svg viewBox='0 0 183.1 378' class='map' role='img' xmlns='http://www.w3.org/2000/svg'>"
  foreach($code in ($code2name.Keys | Sort-Object)){
    $v=$rates[$code]; $d=$gp[$code]; $col=ColorFor $v
    $svg+="<path d='$d' fill='$col' stroke='oklch(0.99 0 0 / .55)' stroke-width='.4'><title>$($code2name[$code]): $($v.ToString('0.0').Replace('.',','))%</title></path>"
  }
  $svg+"</svg>"
}
$mapG=BuildMap $rG; $mapB=BuildMap $rB; $map5=BuildMap $r5; $map9=BuildMap $r9; $map7=BuildMap $r17

# ===== grafico de linea: tendencia nacional 4 periodos =====
$au=@($T17,$T19,$T23,$T25)
$inf=@($null,$null,13.9,22.1)
$xlab=@(@('2017','PASO'),@('2019','PASO'),@('2023','General'),@('2025','Legisl.'))
$lx=@(); for($i=0;$i -lt 4;$i++){ $lx+=[math]::Round(46+$i*116,1) }
function LY($v){ [math]::Round(198-($v/35.0)*172,1) }
$ls="<svg viewBox='0 0 440 244' class='line' role='img' xmlns='http://www.w3.org/2000/svg'>"
foreach($gv in 0,10,20,30){ $gy=LY $gv; $ls+="<line x1='46' x2='418' y1='$gy' y2='$gy' stroke='oklch(0.9 0.008 75)' stroke-width='1'/><text x='40' y='$($gy+3.5)' text-anchor='end' font-size='10' fill='oklch(0.62 0.012 70)'>$gv%</text>" }
$ptsA=''; for($i=0;$i -lt 4;$i++){ $ptsA+="$($lx[$i]),$(LY $au[$i]) " }
$ls+="<polyline points='$($ptsA.Trim())' fill='none' stroke='oklch(0.4 0.02 250)' stroke-width='2.6' stroke-linejoin='round'/>"
for($i=0;$i -lt 4;$i++){ $vy=LY $au[$i]; $vs=$au[$i].ToString('0.0').Replace('.',','); $ls+="<circle cx='$($lx[$i])' cy='$vy' r='4' fill='oklch(0.4 0.02 250)'/><text x='$($lx[$i])' y='$($vy-9)' text-anchor='middle' font-size='11' font-weight='700' fill='oklch(0.4 0.02 250)'>$vs%</text>" }
$ls+="<polyline points='$($lx[2]),$(LY 13.9) $($lx[3]),$(LY 22.1)' fill='none' stroke='oklch(0.56 0.16 32)' stroke-width='2.6' stroke-dasharray='5 3' stroke-linejoin='round'/>"
foreach($p in @(@(2,13.9),@(3,22.1))){ $vy=LY $p[1]; $vs=([double]$p[1]).ToString('0.0').Replace('.',','); $ls+="<circle cx='$($lx[$p[0]])' cy='$vy' r='4' fill='oklch(0.56 0.16 32)'/><text x='$($lx[$p[0]])' y='$($vy+15)' text-anchor='middle' font-size='11' font-weight='700' fill='oklch(0.56 0.16 32)'>$vs%</text>" }
for($i=0;$i -lt 4;$i++){ $ls+="<text x='$($lx[$i])' y='216' text-anchor='middle' font-size='11' font-weight='700' fill='oklch(0.26 0.02 60)'>$($xlab[$i][0])</text><text x='$($lx[$i])' y='230' text-anchor='middle' font-size='9' fill='oklch(0.62 0.012 70)'>$($xlab[$i][1])</text>" }
$lineSvg=$ls+"</svg>"
# data-csv para la linea de tendencia (JSON de filas)
$lineCsvRows=@('["Eleccion","Ausentismo %","Infraccion %"]')
for($i=0;$i -lt 4;$i++){
  $el="$($xlab[$i][1]) $($xlab[$i][0])"
  $av=$au[$i].ToString('0.0').Replace('.',',')
  $iv= if($null -eq $inf[$i]){''} else { ([double]$inf[$i]).ToString('0.0').Replace('.',',') }
  $lineCsvRows+=("[""$el"",""$av"",""$iv""]")
}
$lineCsv='['+($lineCsvRows -join ',')+']'

# ===== JS de exportacion (datos CSV + imagen PNG por elemento .exp) =====
$exportJs = @'
<script>
(function(){
  var _css=null;
  function pageCss(){if(_css===null){_css='';document.querySelectorAll('style').forEach(function(s){_css+=s.textContent})}return _css}
  function toPng(el){
    var rect=el.getBoundingClientRect();
    var tbl=el.querySelector('table');
    var w=Math.ceil(Math.max(rect.width, el.scrollWidth, tbl?tbl.scrollWidth:0));
    var h=Math.ceil(Math.max(rect.height, el.scrollHeight));
    var clone=el.cloneNode(true);
    clone.querySelectorAll('.exp-tools').forEach(function(n){n.remove()});
    clone.querySelectorAll('.tot-wrap,.tbl-wrap').forEach(function(n){n.style.overflow='visible'});
    var paper=getComputedStyle(document.documentElement).getPropertyValue('--paper').trim()||'#fff';
    var xhtml=new XMLSerializer().serializeToString(clone);
    var svg='<svg xmlns="http://www.w3.org/2000/svg" width="'+w+'" height="'+h+'"><foreignObject width="100%" height="100%"><div xmlns="http://www.w3.org/1999/xhtml" style="background:'+paper+';width:'+w+'px;padding:0;margin:0"><style>'+pageCss()+'</style>'+xhtml+'</div></foreignObject></svg>';
    var url='data:image/svg+xml;charset=utf-8,'+encodeURIComponent(svg);
    return new Promise(function(res,rej){
      var img=new Image();
      var to=setTimeout(function(){rej(new Error('timeout'))},12000);
      img.onload=function(){clearTimeout(to);var sc=2;var c=document.createElement('canvas');c.width=w*sc;c.height=h*sc;var cx=c.getContext('2d');cx.scale(sc,sc);cx.drawImage(img,0,0,w,h);c.toBlob(function(b){b?res(b):rej(new Error('toBlob'))},'image/png')};
      img.onerror=function(){clearTimeout(to);rej(new Error('imgload'))};
      img.src=url;
    });
  }
  function txt(n){return n?n.textContent.replace(/\s+/g,' ').trim():''}
  function slug(s){return (s||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'').slice(0,60)||'export'}
  function save(name,blob){var u=URL.createObjectURL(blob);var a=document.createElement('a');a.href=u;a.download=name;document.body.appendChild(a);a.click();a.remove();setTimeout(function(){URL.revokeObjectURL(u)},1500)}
  function csvCell(s){s=(s==null?'':String(s));return /[";\n]/.test(s)?'"'+s.replace(/"/g,'""')+'"':s}
  function toCsv(rows){return '﻿'+rows.map(function(r){return r.map(csvCell).join(';')}).join('\r\n')}
  var EX={
    table:function(el){var t=el.querySelector('table');var out=[];Array.prototype.forEach.call(t.rows,function(r){out.push(Array.prototype.map.call(r.cells,txt))});return out},
    tottbl:function(el){var t=el.querySelector('table');var h=Array.prototype.map.call(t.tHead.rows[0].cells,txt);var Hd=['Provincia'];for(var i=1;i<h.length;i++){Hd.push(h[i]+' tasa%');Hd.push(h[i]+' no votantes')}var out=[Hd];Array.prototype.forEach.call(t.tBodies,function(tb){Array.prototype.forEach.call(tb.rows,function(r){var o=[txt(r.cells[0])];for(var j=1;j<r.cells.length;j++){var c=r.cells[j];o.push(txt(c.querySelector('b')));o.push(txt(c.querySelector('.tcn')))}out.push(o)})});return out},
    comp:function(el){var out=[['Categoria','Personas','Detalle']];el.querySelectorAll('.complegend>div').forEach(function(d){var inner=d.querySelector('div');var num=txt(inner.querySelector('b'));var small=txt(inner.querySelector('small'));var label=txt(inner).replace(num,'').replace(small,'').trim();out.push([label,num,small])});return out},
    pyramid:function(el){var out=[['Edad','Mujeres','Varones']];el.querySelectorAll('.py-row').forEach(function(r){out.push([txt(r.querySelector('.py-lab')),txt(r.querySelector('.py-fnum')),txt(r.querySelector('.py-mnum'))])});return out},
    ranking:function(el){var out=[['Provincia','Ausentismo','Infraccion efectiva']];el.querySelectorAll('.rl-row').forEach(function(r){out.push([txt(r.querySelector('.rl-name')).replace(/^\d+\s*/,''),txt(r.querySelector('.rl-aus span')),txt(r.querySelector('.rl-inf span'))])});return out},
    cmplist:function(el){var hs=[];el.querySelectorAll('.cmp-head>div').forEach(function(d){hs.push(txt(d))});var out=[hs];el.querySelectorAll('.cmp-row').forEach(function(r){var row=[txt(r.querySelector('.cmp-name'))];r.querySelectorAll('.cmp-b span').forEach(function(s){row.push(txt(s))});row.push(txt(r.querySelector('.cmp-d')));out.push(row)});return out},
    map:function(el){var out=[['Provincia','Tasa ausentismo']];el.querySelectorAll('title').forEach(function(t){var p=txt(t).split(':');if(p.length>=2)out.push([p[0].trim(),p.slice(1).join(':').trim()])});return out},
    card:function(el){return EX.table(el)},
    attr:function(el){return JSON.parse(el.getAttribute('data-csv'))}
  };
  function doCsv(el){var kind=el.getAttribute('data-kind');var title=el.getAttribute('data-title')||'datos';try{var rows=EX[kind](el);save(slug(title)+'.csv',new Blob([toCsv(rows)],{type:'text/csv;charset=utf-8'}))}catch(e){console.error(e);alert('No se pudieron extraer los datos de este elemento')}}
  function doPng(el,btn){var title=el.getAttribute('data-title')||'grafico';btn.disabled=true;var old=btn.textContent;btn.textContent='...';toPng(el).then(function(b){save(slug(title)+'.png',b)}).catch(function(e){console.error(e);alert('No se pudo generar la imagen')}).then(function(){btn.disabled=false;btn.textContent=old})}
  document.querySelectorAll('.exp').forEach(function(el){
    if(el.querySelector(':scope>.exp-tools'))return;
    var bar=document.createElement('div');bar.className='exp-tools';
    var bc=document.createElement('button');bc.type='button';bc.textContent='datos';bc.title='Descargar datos (CSV)';bc.addEventListener('click',function(){doCsv(el)});
    var bp=document.createElement('button');bp.type='button';bp.textContent='imagen';bp.title='Descargar imagen (PNG)';bp.addEventListener('click',function(){doPng(el,bp)});
    bar.appendChild(bc);bar.appendChild(bp);el.insertBefore(bar,el.firstChild);
  });
  // ===== picker lateral: destacar provincias en el grafico de lineas =====
  document.querySelectorAll('.mline-layout').forEach(function(layout){
    var svg=layout.querySelector('.mline');var picker=layout.querySelector('.prov-picker');
    if(!svg||!picker)return;
    var PAL=['oklch(0.55 0.17 30)','oklch(0.5 0.12 250)','oklch(0.55 0.13 152)','oklch(0.62 0.14 65)','oklch(0.5 0.15 320)','oklch(0.52 0.1 210)','oklch(0.58 0.15 130)','oklch(0.48 0.14 12)'];
    var pins={},used={},lines={};
    function prev(p,on){if(on){p.style.stroke='var(--ink)';p.style.strokeWidth='2.4';p.parentNode.appendChild(p);}else{p.style.stroke='';p.style.strokeWidth='';}}
    function freeColor(){for(var i=0;i<PAL.length;i++){if(!used[PAL[i]])return PAL[i];}return PAL[Object.keys(pins).length%PAL.length];}
    function toggle(nm,b){var p=lines[nm];if(!p)return;
      if(pins[nm]){used[pins[nm]]=false;delete pins[nm];b.classList.remove('on');b.querySelector('.pp-sw').style.background='';p.style.stroke='';p.style.strokeWidth='';}
      else{var c=freeColor();used[c]=true;pins[nm]=c;b.classList.add('on');b.querySelector('.pp-sw').style.background=c;p.style.stroke=c;p.style.strokeWidth='2.6';p.parentNode.appendChild(p);}
      svg.classList.toggle('has-sel',Object.keys(pins).length>0);}
    var head=document.createElement('div');head.className='pp-head';head.textContent='Toca para destacar';picker.appendChild(head);
    svg.querySelectorAll('.pl').forEach(function(p){
      var t=p.querySelector('title');if(!t)return;
      var raw=t.textContent;var nm=raw.split('—')[0].trim();if(!nm)return;
      lines[nm]=p;
      var mv=raw.match(/2025\s+([0-9.,]+%)/);var v25=mv?mv[1]:'';
      var b=document.createElement('button');b.type='button';b.className='pp-item';b.setAttribute('data-prov',nm);
      b.innerHTML="<span class='pp-sw'></span><span class='pp-nm'></span><span class='pp-v'></span>";
      b.querySelector('.pp-nm').textContent=nm;b.querySelector('.pp-v').textContent=v25;
      picker.appendChild(b);
      b.addEventListener('click',function(){toggle(nm,b)});
      b.addEventListener('mouseenter',function(){if(!pins[nm])prev(p,true)});
      b.addEventListener('mouseleave',function(){if(!pins[nm])prev(p,false)});
    });
  });
})();
</script>
